// Synchronous callback — runs immediately
[1, 2, 3].forEach(function(num) {
  console.log(num); // 1, 2, 3
});

// Asynchronous callback — runs later
setTimeout(function() {
  console.log('1 second later');
}, 1000);

// Callback pattern for async operations
function readFile(path, callback) {
  // simulate async
  setTimeout(() => {
    const data = `content of ${path}`;
    callback(null, data);    // (error, result) convention
  }, 500);
}

readFile('./notes.txt', function(err, data) {
  if (err) return console.error(err);
  console.log(data);
});

// Callback hell (avoid!)
readFile('a.txt', function(err, a) {
  readFile('b.txt', function(err, b) {
    readFile('c.txt', function(err, c) {
      // deeply nested — hard to read
    });
  });
});
